import { SeedApiClient } from "../../src/Client";
import { mockServerPool } from "../mock-server/MockServerPool";

describe("MigrationClient", () => {
    test("getattemptedmigrations", async () => {
        const server = mockServerPool.createServer();
        const client = new SeedApiClient({ maxRetries: 0, token: "test", environment: server.baseUrl });

        const rawResponseBody = [{ name: "name", status: "RUNNING" }];

        server
            .mockEndpoint()
            .get("/migration-info/all")
            .header("admin-key-header", "admin-key-header")
            .respondWith()
            .statusCode(200)
            .jsonBody(rawResponseBody)
            .build();

        const response = await client.migration.getattemptedmigrations({
            adminKeyHeader: "admin-key-header",
        });
        expect(response).toEqual([
            {
                name: "name",
                status: "RUNNING",
            },
        ]);
    });
});
